SELECT id, unique_id, video_url, video_create_time , video_desc , video_collect_count, video_comment_count , video_digg_count, video_play_count, video_share_count, batch_no, user_id, author_id, nick_name, sec_uid, video_id FROM tiktok_video
AND unique_id = #{tiktokVideoModel.uniqueId}
AND video_url = '${tiktokVideoModel.videoUrl}'
AND batch_no = #{tiktokVideoModel.batchNo}
AND user_id = #{tiktokVideoModel.userId}
AND create_time >= #{tiktokVideoModel.startDateTime}
AND create_time <= #{tiktokVideoModel.endDateTime}
order by id asc

SELECT id, unique_id, video_url, video_create_time , video_desc , video_collect_count, video_comment_count , video_digg_count, video_play_count, video_share_count, video_id, author_id, nick_name, sec_uid, batch_no, user_id, user_name, remark, create_time FROM tiktok_video
AND unique_id = #{tiktokVideoModel.uniqueId}
AND video_url = '${tiktokVideoModel.videoUrl}'
AND batch_no = #{tiktokVideoModel.batchNo}
AND user_id = #{tiktokVideoModel.userId}
AND create_time >= #{tiktokVideoModel.startDateTime}
AND create_time <= #{tiktokVideoModel.endDateTime}
order by create_time desc
